import{_ as e,c as a,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Backup & Migrate: JSON Import/Export | Antigravity-Manager","description":"Learn Antigravity-Manager account backup and migration. Export refresh_token as JSON for one-click import on new machines. Import from Antigravity/IDE state.vscdb or V1 data directory. Use auto-sync to keep current account synced with local login state changes.","frontmatter":{"title":"Backup & Migrate: JSON Import/Export | Antigravity-Manager","sidebarTitle":"Backup & Migrate","subtitle":"Backup & Migrate: JSON Import/Export, V1/DB Hot Migration","description":"Learn Antigravity-Manager account backup and migration. Export refresh_token as JSON for one-click import on new machines. Import from Antigravity/IDE state.vscdb or V1 data directory. Use auto-sync to keep current account synced with local login state changes.","tags":["Account Management","Backup","Migration","Import/Export","state.vscdb"],"prerequisite":["start-add-account","start-first-run-data"],"duration":12,"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/start/backup-migrate/index.md","filePath":"lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"}'),r={name:"lbjlaq/Antigravity-Manager/start/backup-migrate/index.md"};function n(s,t,l,c,d,p){return o(),a("div",null,[...t[0]||(t[0]=[i(`<h1 id="account-backup-migration-import-export-v1-db-hot-migration" tabindex="-1">Account Backup &amp; Migration: Import/Export, V1/DB Hot Migration <a class="header-anchor" href="#account-backup-migration-import-export-v1-db-hot-migration" aria-label="Permalink to &quot;Account Backup &amp; Migration: Import/Export, V1/DB Hot Migration&quot;">​</a></h1><p>What you really want to &quot;backup&quot; isn&#39;t the quota number, but the <code>refresh_token</code> that lets the account log back in. This lesson explains Antigravity Tools&#39; migration methods: JSON import/export, importing from <code>state.vscdb</code>, importing from V1 data directory, and how auto-sync works.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Export your account pool as a JSON file (containing only email + refresh_token)</li><li>Import this JSON on a new machine to quickly restore your account pool</li><li>Directly import &quot;currently logged-in account&quot; from Antigravity/IDE&#39;s <code>state.vscdb</code> (supports default path and custom path)</li><li>Automatically scan and import old accounts from V1 data directory</li><li>Understand what &quot;auto-sync current account&quot; actually does and when it skips</li></ul><h2 id="your-current-pain-points" tabindex="-1">Your Current Pain Points <a class="header-anchor" href="#your-current-pain-points" aria-label="Permalink to &quot;Your Current Pain Points&quot;">​</a></h2><ul><li>After reinstalling system or switching computers, you need to re-add all accounts to the pool, which is costly</li><li>You switched logged-in accounts in Antigravity/IDE, but Manager&#39;s &quot;current account&quot; didn&#39;t follow</li><li>You previously used V1/script version and only have old data files, unsure if they can be directly migrated</li></ul><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><ul><li>You want to move your account pool to another machine (desktop/server/container)</li><li>You treat Antigravity as the &quot;authoritative login entry&quot; and want Manager to auto-sync current account</li><li>You want to migrate accounts from old version (V1 data directory)</li></ul><h2 id="🎒-preparation" tabindex="-1">🎒 Preparation <a class="header-anchor" href="#🎒-preparation" aria-label="Permalink to &quot;🎒 Preparation&quot;">​</a></h2><ul><li>You can open Antigravity Tools and have at least one account in the account pool</li><li>You understand that account data is sensitive information (especially <code>refresh_token</code>)</li></ul><div class="warning custom-block"><p class="custom-block-title">Security Reminder: Treat backup files like passwords</p><p>The exported JSON file contains <code>refresh_token</code>. Anyone who obtains it could use it to refresh access tokens. Don&#39;t upload backup files to public cloud storage links, don&#39;t share in groups, don&#39;t commit to Git.</p></div><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>Antigravity Tools&#39; &quot;migration&quot; essentially does two things:</p><ol><li>Find available <code>refresh_token</code></li><li>Use it to exchange for access token, fetch real email from Google, then write the account into local account pool</li></ol><p>It provides three entry points:</p><ul><li>JSON Import/Export: suitable when you explicitly want &quot;controlled backup&quot;</li><li>DB Import: suitable when you treat Antigravity/IDE&#39;s login state as authoritative source (defaults to finding <code>state.vscdb</code>, also supports manual file selection)</li><li>V1 Import: suitable for automatically scanning and migrating from old data directory</li></ul><p>Additionally, there&#39;s &quot;auto-sync&quot;: it periodically reads refresh_token from DB, and if different from Manager&#39;s current account, automatically performs a DB import; if same, it skips (saving traffic).</p><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-export-account-pool-json-backup" tabindex="-1">Step 1: Export Account Pool (JSON Backup) <a class="header-anchor" href="#step-1-export-account-pool-json-backup" aria-label="Permalink to &quot;Step 1: Export Account Pool (JSON Backup)&quot;">​</a></h3><p><strong>Why</strong> This is the most stable, controllable migration method. You get a file and can restore the account pool on another machine.</p><p>Operation: Go to <code>Accounts</code> page, click export button.</p><ul><li>If you configured <code>default_export_path</code> in settings, export will write directly to that directory using filename <code>antigravity_accounts_YYYY-MM-DD.json</code>.</li><li>If default directory is not configured, a system save dialog will pop up for you to choose the path.</li></ul><p>Export file content roughly looks like this (each item in array keeps only necessary fields):</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;alice@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//xxxxxxxxxxxxxxxxxxxxxxxx&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;email&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;bob@example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;refresh_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1//yyyyyyyyyyyyyyyyyyyyyyyy&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p><strong>You should see</strong>: Page displays export success message and shows save path.</p><h3 id="step-2-import-json-on-new-machine-restore-account-pool" tabindex="-1">Step 2: Import JSON on New Machine (Restore Account Pool) <a class="header-anchor" href="#step-2-import-json-on-new-machine-restore-account-pool" aria-label="Permalink to &quot;Step 2: Import JSON on New Machine (Restore Account Pool)&quot;">​</a></h3><p><strong>Why</strong> Import will call &quot;add account&quot; logic one by one, use <code>refresh_token</code> to fetch real email and write into account pool.</p><p>Operation: Still on <code>Accounts</code> page, click &quot;Import JSON&quot;, choose the file you just exported.</p><p>Format requirements as follows (at least 1 valid record required):</p><ul><li>Must be a JSON array</li><li>System will only import entries containing <code>refresh_token</code> that start with <code>1//</code></li></ul><p><strong>You should see</strong>: After import finishes, imported accounts appear in account list.</p><div class="tip custom-block"><p class="custom-block-title">If Proxy is running when you import</p><p>After each successful &quot;add account&quot;, backend will try to reload reverse-proxy token pool, making new accounts take effect immediately.</p></div><h3 id="step-3-import-currently-logged-in-account-from-state-vscdb" tabindex="-1">Step 3: Import &quot;Currently Logged-In Account&quot; from <code>state.vscdb</code> <a class="header-anchor" href="#step-3-import-currently-logged-in-account-from-state-vscdb" aria-label="Permalink to &quot;Step 3: Import &quot;Currently Logged-In Account&quot; from \`state.vscdb\`&quot;">​</a></h3><p><strong>Why</strong> Sometimes you don&#39;t want to maintain backup files, just want &quot;use Antigravity/IDE&#39;s login state as the source of truth&quot;. DB import is prepared for this scenario.</p><p>Operation: Go to <code>Accounts</code> page, click <strong>Add Account</strong>, switch to <code>Import</code> tab:</p><ul><li>Click &quot;Import from Database&quot; (use default DB path)</li><li>Or click &quot;Custom DB (state.vscdb)&quot; to manually select a <code>*.vscdb</code> file</li></ul><p>Default DB path is cross-platform (also prioritizes recognizing <code>--user-data-dir</code> or portable mode):</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-zRR7u" id="tab-RTcaeA3" checked><label data-title="macOS" for="tab-RTcaeA3">macOS</label><input type="radio" name="group-zRR7u" id="tab-WnomOoc"><label data-title="Windows" for="tab-WnomOoc">Windows</label><input type="radio" name="group-zRR7u" id="tab-sYKTR9K"><label data-title="Linux" for="tab-sYKTR9K">Linux</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/Library/Application Support/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>%APPDATA%\\Antigravity\\User\\globalStorage/state.vscdb</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.config/Antigravity/User/globalStorage/state.vscdb</span></span></code></pre></div></div></div><p><strong>You should see</strong>:</p><ul><li>After successful import, this account will be automatically set as Manager&#39;s &quot;current account&quot;</li><li>System will automatically trigger a quota refresh</li></ul><h3 id="step-4-migrate-from-v1-data-directory-old-version-import" tabindex="-1">Step 4: Migrate from V1 Data Directory (Old Version Import) <a class="header-anchor" href="#step-4-migrate-from-v1-data-directory-old-version-import" aria-label="Permalink to &quot;Step 4: Migrate from V1 Data Directory (Old Version Import)&quot;">​</a></h3><p><strong>Why</strong> If you previously used V1/script version, Manager allows you to directly scan old data directory and try to import.</p><p>Operation: On <code>Import</code> tab, click &quot;Import V1&quot;.</p><p>It will look for this path in your home directory (and its index files):</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.antigravity-agent/</span></span>
<span class="line"><span>  - antigravity_accounts.json</span></span>
<span class="line"><span>  - accounts.json</span></span></code></pre></div><p><strong>You should see</strong>: After import completes, accounts appear in list; if index files not found, backend will return error <code>V1 account data file not found</code>.</p><h3 id="step-5-optional-enable-auto-sync-current-account" tabindex="-1">Step 5 (Optional): Enable &quot;Auto-Sync Current Account&quot; <a class="header-anchor" href="#step-5-optional-enable-auto-sync-current-account" aria-label="Permalink to &quot;Step 5 (Optional): Enable &quot;Auto-Sync Current Account&quot;&quot;">​</a></h3><p><strong>Why</strong> When you switch logged-in accounts in Antigravity/IDE, Manager can detect at fixed intervals whether refresh_token in DB changed, and automatically import when changed.</p><p>Operation: Go to <code>Settings</code>, enable <code>auto_sync</code>, and set <code>sync_interval</code> (unit: seconds).</p><p><strong>You should see</strong>: Immediately executes one sync after enabling; thereafter executes periodically at interval. If refresh_token in DB is same as current account, it will skip directly and not repeatedly import.</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>You can see imported accounts in <code>Accounts</code> list</li><li>You can see &quot;current account&quot; has switched to your expected one (DB import automatically sets as current)</li><li>After you start Proxy, newly imported accounts can be normally used for requests (based on actual call results)</li></ul><h2 id="pitfall-warnings" tabindex="-1">Pitfall Warnings <a class="header-anchor" href="#pitfall-warnings" aria-label="Permalink to &quot;Pitfall Warnings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>What you might do (❌)</th><th>Recommended approach (✓)</th></tr></thead><tbody><tr><td>Backup file security</td><td>Treat exported JSON as normal config file and casually share it</td><td>Treat JSON as password, minimize spread scope, avoid public internet exposure</td></tr><tr><td>JSON import failed</td><td>JSON is not an array, or refresh_token doesn&#39;t have <code>1//</code> prefix</td><td>Use JSON exported by this project as template, keep field names and structure consistent</td></tr><tr><td>DB import can&#39;t find data</td><td>Antigravity hasn&#39;t logged in, or DB is missing <code>jetskiStateSync.agentManagerInitState</code></td><td>First confirm Antigravity/IDE has logged in, then try import; if necessary use Custom DB to select correct file</td></tr><tr><td>Account unusable after V1 import</td><td>Old refresh_token expired</td><td>Delete that account and re-add with OAuth/new refresh_token (follow error prompt)</td></tr><tr><td>auto_sync too frequent</td><td><code>sync_interval</code> set very small, frequently scanning DB</td><td>Treat it as &quot;state following&quot;, set interval to a frequency you can accept</td></tr></tbody></table><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>JSON export/import is the most controllable migration method: backup file only keeps <code>email + refresh_token</code></li><li>DB import is suitable for &quot;use Antigravity/IDE&#39;s currently logged-in account as the source of truth&quot;, and will automatically set as Manager&#39;s current account</li><li>V1 import scans <code>~/.antigravity-agent</code> and is compatible with multiple old formats</li><li>auto_sync compares refresh_token; same ones are skipped, no repeated import</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll put &quot;migrated account pool&quot; to real use: <strong><a href="./../proxy-and-first-client/">Start local reverse-proxy and integrate first client (/healthz + SDK configuration)</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>How to start/stop Proxy, and use <code>/healthz</code> for minimal verification</li><li>How to configure Base URL in SDK/client</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Accounts export/import JSON (<code>save_text_file</code> / <code>read_text_file</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Accounts.tsx#L458-L578" target="_blank" rel="noreferrer"><code>src/pages/Accounts.tsx</code></a></td><td>458-578</td></tr><tr><td>Dashboard export account JSON</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Dashboard.tsx#L113-L148" target="_blank" rel="noreferrer"><code>src/pages/Dashboard.tsx</code></a></td><td>113-148</td></tr><tr><td>Import tab: DB import / Custom DB / V1 import buttons</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/accounts/AddAccountDialog.tsx#L491-L539" target="_blank" rel="noreferrer"><code>src/components/accounts/AddAccountDialog.tsx</code></a></td><td>491-539</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>DB import: extract refresh_token from <code>state.vscdb</code> (ItemTable + base64 + protobuf)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/migration.rs#L192-L267" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/migration.rs</code></a></td><td>192-267</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>auto_sync: compare refresh_token, skip if same; trigger DB import if changed</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L532-L564" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>532-564</td></tr><tr><td>Frontend background task: periodically call <code>syncAccountFromDb()</code> by <code>sync_interval</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/common/BackgroundTaskRunner.tsx#L43-L72" target="_blank" rel="noreferrer"><code>src/components/common/BackgroundTaskRunner.tsx</code></a></td><td>43-72</td></tr></tbody></table></details>`,61)])])}const m=e(r,[["render",n]]);export{h as __pageData,m as default};
